import { initializeApp, type FirebaseApp } from 'firebase/app';
import {
  getAuth,
  GoogleAuthProvider,
  signInWithPopup,
  signOut as firebaseSignOut,
  onAuthStateChanged,
  type Auth,
} from 'firebase/auth';
import {
  getFirestore,
  doc,
  getDoc,
  setDoc,
  updateDoc,
  deleteDoc,
  collection,
  getDocs,
  query,
  where,
  addDoc,
  type Firestore,
} from 'firebase/firestore';

import seededData from '@/data/seeded_students.json';
import type {
  StudentProfile,
  UnclaimedStudent,
  MatchRequest,
  AvailabilityResult,
  MockUser,
  SeededData,
} from '@/types';

const data = seededData as SeededData;

// ── Firebase Config ──────────────────────────────────────────────────────────
const firebaseConfig = {
  apiKey:            process.env.NEXT_PUBLIC_FIREBASE_API_KEY,
  authDomain:        process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN,
  projectId:         process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID,
  storageBucket:     process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID,
  appId:             process.env.NEXT_PUBLIC_FIREBASE_APP_ID,
};

export const USE_MOCK = !(
  firebaseConfig.apiKey &&
  firebaseConfig.projectId &&
  firebaseConfig.authDomain
);

let app: FirebaseApp | undefined;
let auth: Auth | undefined;
let db: Firestore | undefined;

if (!USE_MOCK) {
  app  = initializeApp(firebaseConfig);
  auth = getAuth(app);
  db   = getFirestore(app);
}

// ── Local Storage keys ────────────────────────────────────────────────────────
const K_AUTH        = 'bunkr_mock_auth_user';
const K_STUDENTS    = 'bunkr_mock_students';
const K_UNCLAIMED   = 'bunkr_mock_unclaimed';
const K_REQUESTS    = 'bunkr_mock_requests';
const K_DEMO_SEEDED = 'bunkr_demo_seeded_v2';
const AUTH_EVENT    = 'bunkr-auth-change';

const mockUid = (email: string) => 'mock_' + email.replace(/[^a-zA-Z0-9]/g, '_');

function notifyAuthChange() {
  if (typeof window !== 'undefined') window.dispatchEvent(new Event(AUTH_EVENT));
}

function buildDemoProfile(
  email: string,
  name: string,
  course: string,
  semester: string,
  currentRoom: string | null,
  currentFloor: string | null,
  preferredFloor: string,
  bio: string,
  prefs: Partial<StudentProfile['preferences']>,
): StudentProfile {
  const now = new Date().toISOString();
  return {
    uid: mockUid(email),
    name,
    email,
    course,
    semester,
    currentRoom,
    currentFloor,
    preferredFloor,
    lookingForRoommate: true,
    sgpa: 8.2,
    cgpa: 8.4,
    backlog: false,
    preferences: {
      sleepSchedule: 'flexible',
      cleanliness: 'average',
      smoking: 'non-smoker',
      foodType: 'veg',
      language: ['Hindi', 'English'],
      studyStyle: 'silent study',
      noiseTolerance: 'medium',
      guestsOk: true,
      hobbies: ['gaming', 'music'],
      ...prefs,
    },
    utilities: {
      acCoolerNeed: 'either',
      cleaningRotation: true,
      billSharing: true,
    },
    bio,
    photoURL: `https://api.dicebear.com/7.x/bottts/svg?seed=${encodeURIComponent(email)}`,
    updatedAt: now,
  };
}

function seedDemoData() {
  const profiles: Record<string, StudentProfile> = {
    [mockUid('saurabh@upsifs.ac.in')]: buildDemoProfile(
      'saurabh@upsifs.ac.in', 'Saurabh Nirmal', 'BTech Mtech', '4th Sem',
      '1', 'Ground', 'First',
      'Early riser, loves cricket & forensic documentaries.',
      { sleepSchedule: 'early bird', foodType: 'veg', hobbies: ['sports', 'reading', 'movies'] },
    ),
    [mockUid('harshit@upsifs.ac.in')]: buildDemoProfile(
      'harshit@upsifs.ac.in', 'Harshit', 'Bsc LLB', '4th Sem',
      '1', 'Ground', 'Ground',
      'Night owl coder. Quiet room, loud headphones.',
      { sleepSchedule: 'night owl', foodType: 'non-veg', studyStyle: 'music while studying', hobbies: ['coding', 'gaming', 'anime'] },
    ),
    [mockUid('vikrant@upsifs.ac.in')]: buildDemoProfile(
      'vikrant@upsifs.ac.in', 'Vikrant Tiwari', 'BTech Mtech', '4th Sem',
      '103', 'First', 'Second',
      'Gym rat. Needs a tidy roommate who splits bills.',
      { sleepSchedule: 'early bird', cleanliness: 'very tidy', foodType: 'eggetarian', hobbies: ['gym', 'cooking'] },
    ),
    [mockUid('ankur@upsifs.ac.in')]: buildDemoProfile(
      'ankur@upsifs.ac.in', 'Ankur Mishra', 'Bsc Msc', '4th Sem',
      '5', 'Ground', 'First',
      'Group study person. OK with guests on weekends.',
      { sleepSchedule: 'flexible', studyStyle: 'group study', guestsOk: true, hobbies: ['music', 'photography'] },
    ),
  };

  const claimed = new Set(Object.values(profiles).map((p) => p.name.toLowerCase()));
  const unclaimed = data.students.filter((s) => !claimed.has(s.name.toLowerCase()));

  localStorage.setItem(K_STUDENTS, JSON.stringify(profiles));
  localStorage.setItem(K_UNCLAIMED, JSON.stringify(unclaimed));
  localStorage.setItem(K_REQUESTS, JSON.stringify([
    {
      id: 'req_demo_1',
      fromUid: mockUid('harshit@upsifs.ac.in'),
      toUid: mockUid('saurabh@upsifs.ac.in'),
      status: 'pending',
      createdAt: new Date(Date.now() - 86400000).toISOString(),
    },
  ]));
}

const getUnclaimed = (): UnclaimedStudent[] =>
  typeof window !== 'undefined'
    ? JSON.parse(localStorage.getItem(K_UNCLAIMED) || '[]')
    : [];
const setUnclaimed = (d: UnclaimedStudent[]) =>
  localStorage.setItem(K_UNCLAIMED, JSON.stringify(d));

const getStudents = (): Record<string, StudentProfile> =>
  typeof window !== 'undefined'
    ? JSON.parse(localStorage.getItem(K_STUDENTS) || '{}')
    : {};
const setStudents = (d: Record<string, StudentProfile>) =>
  localStorage.setItem(K_STUDENTS, JSON.stringify(d));

const getRequests = (): MatchRequest[] =>
  typeof window !== 'undefined'
    ? JSON.parse(localStorage.getItem(K_REQUESTS) || '[]')
    : [];
const setRequests = (d: MatchRequest[]) =>
  localStorage.setItem(K_REQUESTS, JSON.stringify(d));

function initMock() {
  if (typeof window === 'undefined') return;
  if (!localStorage.getItem(K_UNCLAIMED))
    localStorage.setItem(K_UNCLAIMED, JSON.stringify(data.students));
  if (!localStorage.getItem(K_STUDENTS))
    localStorage.setItem(K_STUDENTS, JSON.stringify({}));
  if (!localStorage.getItem(K_REQUESTS))
    localStorage.setItem(K_REQUESTS, JSON.stringify([]));
  if (!localStorage.getItem(K_DEMO_SEEDED)) {
    const existing = JSON.parse(localStorage.getItem(K_STUDENTS) || '{}');
    if (Object.keys(existing).length === 0) seedDemoData();
    localStorage.setItem(K_DEMO_SEEDED, '1');
  }
}
initMock();

// ── Public DB Service ─────────────────────────────────────────────────────────
export const dbService = {
  isDemo: USE_MOCK,

  // Auth
  signInWithGoogleMock: async (email: string, name: string): Promise<MockUser> => {
    if (!email.endsWith('@upsifs.ac.in'))
      throw new Error('Access restricted to UPSIFS accounts (@upsifs.ac.in)');
    const mockUser: MockUser = {
      uid: 'mock_' + email.replace(/[^a-zA-Z0-9]/g, '_'),
      email,
      displayName: name || email.split('@')[0],
      photoURL: `https://api.dicebear.com/7.x/bottts/svg?seed=${encodeURIComponent(email)}`,
    };
    localStorage.setItem(K_AUTH, JSON.stringify(mockUser));
    notifyAuthChange();
    return mockUser;
  },

  signInWithGoogle: async (): Promise<MockUser | null> => {
    if (USE_MOCK) return null;
    const provider = new GoogleAuthProvider();
    provider.setCustomParameters({ prompt: 'select_account' });
    const result = await signInWithPopup(auth!, provider);
    const user = result.user;
    if (!user.email?.endsWith('@upsifs.ac.in')) {
      await firebaseSignOut(auth!);
      throw new Error('Access restricted to UPSIFS accounts (@upsifs.ac.in)');
    }
    return {
      uid: user.uid,
      email: user.email,
      displayName: user.displayName || '',
      photoURL: user.photoURL || '',
    };
  },

  signOut: async () => {
    if (USE_MOCK) {
      localStorage.removeItem(K_AUTH);
      notifyAuthChange();
      return;
    }
    await firebaseSignOut(auth!);
  },

  resetDemoData: () => {
    if (!USE_MOCK || typeof window === 'undefined') return;
    localStorage.removeItem(K_DEMO_SEEDED);
    localStorage.removeItem(K_STUDENTS);
    localStorage.removeItem(K_UNCLAIMED);
    localStorage.removeItem(K_REQUESTS);
    initMock();
  },

  onAuthStateChange: (cb: (u: MockUser | null) => void) => {
    if (USE_MOCK) {
      const check = () => {
        const raw = localStorage.getItem(K_AUTH);
        cb(raw ? JSON.parse(raw) : null);
      };
      check();
      window.addEventListener('storage', check);
      window.addEventListener(AUTH_EVENT, check);
      return () => {
        window.removeEventListener('storage', check);
        window.removeEventListener(AUTH_EVENT, check);
      };
    }
    return onAuthStateChanged(auth!, (u) => {
      if (!u) { cb(null); return; }
      cb({
        uid: u.uid,
        email: u.email || '',
        displayName: u.displayName || '',
        photoURL: u.photoURL || '',
      });
    });
  },

  // Profile
  getStudentProfile: async (uid: string): Promise<StudentProfile | null> => {
    if (USE_MOCK) return getStudents()[uid] ?? null;
    const snap = await getDoc(doc(db!, 'students', uid));
    return snap.exists() ? (snap.data() as StudentProfile) : null;
  },

  saveStudentProfile: async (uid: string, data: Partial<StudentProfile>): Promise<StudentProfile> => {
    const payload = { ...data, updatedAt: new Date().toISOString() } as StudentProfile;
    if (USE_MOCK) {
      const map = getStudents();
      map[uid] = { ...map[uid], ...payload };
      setStudents(map);
      return map[uid];
    }
    await setDoc(doc(db!, 'students', uid), payload, { merge: true });
    return payload;
  },

  // Unclaimed
  getUnclaimedStudents: async (): Promise<UnclaimedStudent[]> => {
    if (USE_MOCK) return getUnclaimed();
    const snap = await getDocs(collection(db!, 'unclaimed_students'));
    return snap.docs.map((d) => d.data() as UnclaimedStudent);
  },

  claimStudentProfile: async (
    uid: string,
    studentName: string,
    finalProfile: Partial<StudentProfile>,
  ): Promise<StudentProfile> => {
    if (USE_MOCK) {
      setUnclaimed(getUnclaimed().filter(
        (s) => s.name.toLowerCase() !== studentName.toLowerCase(),
      ));
      const map = getStudents();
      map[uid] = { uid, name: studentName, ...finalProfile, updatedAt: new Date().toISOString() } as StudentProfile;
      setStudents(map);
      return map[uid];
    }
    const slug = studentName.toLowerCase().replace(/[^a-z0-9]/g, '_');
    try { await deleteDoc(doc(db!, 'unclaimed_students', slug)); } catch {}
    const payload = { uid, name: studentName, ...finalProfile, updatedAt: new Date().toISOString() } as StudentProfile;
    await setDoc(doc(db!, 'students', uid), payload);
    return payload;
  },

  // Directory
  getRegisteredStudents: async (): Promise<StudentProfile[]> => {
    if (USE_MOCK) return Object.values(getStudents());
    const snap = await getDocs(collection(db!, 'students'));
    return snap.docs.map((d) => d.data() as StudentProfile);
  },

  // Floor headcounts
  getPreferredFloorHeadcounts: async (): Promise<Record<string, number>> => {
    const counts: Record<string, number> = { Ground: 0, First: 0, Second: 0 };
    const students = USE_MOCK
      ? Object.values(getStudents())
      : await getDocs(collection(db!, 'students')).then((s) =>
          s.docs.map((d) => d.data() as StudentProfile),
        );
    (students as StudentProfile[]).forEach((s) => {
      if (s.preferredFloor && counts[s.preferredFloor] !== undefined)
        counts[s.preferredFloor]++;
    });
    return counts;
  },

  // Availability check
  checkRoommateAvailability: async (
    names: string[],
  ): Promise<Record<string, AvailabilityResult>> => {
    const results: Record<string, AvailabilityResult> = {};
    const clean = names.map((n) => n.trim().toLowerCase()).filter(Boolean);
    if (!clean.length) return results;

    if (USE_MOCK) {
      const registered = Object.values(getStudents());
      const unclaimed  = getUnclaimed();
      clean.forEach((target) => {
        const reg = registered.find((s) => s.name.toLowerCase() === target);
        if (reg) {
          if (reg.lookingForRoommate && !reg.currentRoom)
            results[target] = { status: 'available', details: 'Available & looking 🟢' };
          else if (reg.currentRoom)
            results[target] = { status: 'allotted', details: `Already allotted — Room ${reg.currentRoom}, ${reg.currentFloor} Floor 🔴` };
          else
            results[target] = { status: 'registered', details: 'Registered but not open to matching ⚪' };
          return;
        }
        const unc = unclaimed.find((s) => s.name.toLowerCase() === target);
        if (unc) {
          results[target] = unc.currentRoom
            ? { status: 'allotted', details: `Already allotted — Room ${unc.currentRoom}, ${unc.currentFloor} Floor 🔴` }
            : { status: 'unregistered', details: 'Not yet registered ⚪' };
          return;
        }
        results[target] = { status: 'unknown', details: 'Not found in records ⚪' };
      });
    }
    return results;
  },

  // Match requests
  sendMatchRequest: async (fromUid: string, toUid: string): Promise<MatchRequest> => {
    const req = { fromUid, toUid, status: 'pending' as const, createdAt: new Date().toISOString() };
    if (USE_MOCK) {
      const list = getRequests();
      if (list.some((r) => r.fromUid === fromUid && r.toUid === toUid && r.status === 'pending'))
        throw new Error('A pending request already exists!');
      const newReq: MatchRequest = { id: `req_${Date.now()}`, ...req };
      setRequests([...list, newReq]);
      return newReq;
    }
    const q = query(
      collection(db!, 'matchRequests'),
      where('fromUid', '==', fromUid),
      where('toUid', '==', toUid),
      where('status', '==', 'pending'),
    );
    if (!(await getDocs(q)).empty) throw new Error('A pending request already exists!');
    const ref = await addDoc(collection(db!, 'matchRequests'), req);
    return { id: ref.id, ...req };
  },

  getMatchRequests: async (uid: string): Promise<MatchRequest[]> => {
    if (USE_MOCK) {
      const students = getStudents();
      return getRequests()
        .filter((r) => r.fromUid === uid || r.toUid === uid)
        .map((r) => {
          const partnerUid = r.fromUid === uid ? r.toUid : r.fromUid;
          const partner = students[partnerUid];
          return {
            ...r,
            direction: r.fromUid === uid ? 'outgoing' : ('incoming' as 'outgoing' | 'incoming'),
            partnerName: partner?.name ?? 'Unknown',
            partnerCourse: partner?.course ?? '—',
            partnerSemester: partner?.semester ?? '—',
            partnerPhoto:
              partner?.photoURL ??
              `https://api.dicebear.com/7.x/bottts/svg?seed=${partnerUid}`,
          };
        });
    }
    return [];
  },

  updateMatchRequest: async (id: string, status: MatchRequest['status']): Promise<void> => {
    if (USE_MOCK) {
      const list = getRequests();
      const idx = list.findIndex((r) => r.id === id);
      if (idx !== -1) { list[idx].status = status; setRequests(list); }
      return;
    }
    await updateDoc(doc(db!, 'matchRequests', id), { status });
  },
};
