'use client';

import { useState, useEffect } from 'react';
import { dbService } from '@/lib/firebase';
import LandingPage from '@/components/LandingPage';
import Onboarding from '@/components/Onboarding';
import Dashboard from '@/components/Dashboard';
import type { StudentProfile, MockUser } from '@/types';

export default function Page() {
  const [user, setUser] = useState<MockUser | null>(null);
  const [profile, setProfile] = useState<StudentProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    const unsubscribe = dbService.onAuthStateChange(async (firebaseUser: MockUser | null) => {
      setLoading(true);
      if (firebaseUser) {
        setUser(firebaseUser);
        try {
          const studentProfile = await dbService.getStudentProfile(firebaseUser.uid);
          setProfile(studentProfile);
        } catch {
          setProfile(null);
        }
      } else {
        setUser(null);
        setProfile(null);
      }
      setLoading(false);
    });
    return () => {
      if (typeof unsubscribe === 'function') unsubscribe();
    };
  }, []);

  const handleLoginSuccess = async (loggedInUser: MockUser) => {
    setLoading(true);
    setUser(loggedInUser);
    try {
      const studentProfile = await dbService.getStudentProfile(loggedInUser.uid);
      setProfile(studentProfile);
    } catch {
      setProfile(null);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    setLoading(true);
    await dbService.signOut();
    setUser(null);
    setProfile(null);
    setLoading(false);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-mesh-light dark:bg-mesh-dark flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="h-10 w-10 rounded-xl bg-brand flex items-center justify-center shadow-lg shadow-orange-500/25 animate-spin">
            <span className="text-white font-black text-lg">B</span>
          </div>
          <p className="text-[11px] font-bold tracking-[0.2em] uppercase text-sage-500 dark:text-sage-400">
            Loading BunkrNFSU…
          </p>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <LandingPage
        onLoginSuccess={handleLoginSuccess}
        darkMode={darkMode}
        setDarkMode={setDarkMode}
      />
    );
  }

  if (!profile) {
    return (
      <Onboarding
        user={user}
        onComplete={(p) => setProfile(p)}
      />
    );
  }

  return (
    <Dashboard
      user={user}
      userProfile={profile}
      onProfileUpdate={(p) => setProfile(p)}
      onLogout={handleLogout}
      darkMode={darkMode}
      setDarkMode={setDarkMode}
    />
  );
}
